import React from 'react';
import CohortDetails from './components/CohortDetails';
function App() {
    const cohorts = [
        {
            cohortName: "INTADMDF10 .NET FSD",
            startDate: "22-Feb-2022",
            status: "Ongoing",
            coach: "John",
            trainer: "Peter"
        },
        {
            cohortName: "ADM21JF014 Java FSD",
            startDate: "10-Sep-2021",
            status: "Completed",
            coach: "David",
            trainer: "Sam"
        }
    ];
    return (
        <div>
            {cohorts.map((cohort, index) => (
                <CohortDetails
                    key={index}
                    cohort={cohort}
                />
            ))}
        </div>
    );
}
export default App;
